SELECT user_id, name, gender, age, height, program_of_study, hobby, location, last_active, verification_status, two_factor_auth, notification_preferences
FROM users
WHERE user_id IN (SELECT blocked_user_id FROM blocks WHERE block_reason = 'inappropriate behavior');

SELECT DISTINCT u.name, u.gender
FROM users u
JOIN matches m ON u.user_id = m.user_id;

SELECT interest
FROM interests
WHERE interest_category = 'gender' AND interest = 'FEMALE';

SELECT name, age
FROM users
WHERE user_id IN (SELECT user_id FROM matches WHERE match_status = 'accepted') AND age < 25;

SELECT 
    (SELECT COUNT(*) FROM blocks WHERE user_id = 0) AS TotalBlockedUsers,
    (SELECT COUNT(*) FROM notifications WHERE user_id = 0) AS TotalNotifications;
